import type * as React from "react";

import type { IconProps } from "./types";

type SvgIconProps = IconProps & {
  children: React.ReactNode;
  fill?: string;
  stroke?: string;
  viewBox?: string;
};

function SvgIcon({
  children,
  fill = "none",
  size = 18,
  stroke,
  title,
  viewBox = "0 0 24 24",
  ...props
}: SvgIconProps) {
  return (
    <svg
      aria-hidden={title ? undefined : true}
      fill={fill}
      height={size}
      stroke={stroke}
      viewBox={viewBox}
      width={size}
      xmlns="http://www.w3.org/2000/svg"
      {...props}
    >
      {title ? <title>{title}</title> : null}
      {children}
    </svg>
  );
}

function FilledPathIcon({
  children,
  ...props
}: IconProps & { children: React.ReactNode }) {
  return (
    <SvgIcon fill="currentColor" {...props}>
      {children}
    </SvgIcon>
  );
}

