export function LoadingIcon({
  size = 18,
  title,
  strokeWidth = 2,
  trackColor,
  ...props
}: LoadingIconProps) {
  return (
    <SvgIcon size={size} title={title} {...props}>
      <circle
        cx="12"
        cy="12"
        opacity={trackColor ? undefined : 0.22}
        r="9"
        stroke={trackColor ?? "currentColor"}
        strokeWidth={strokeWidth}
      />
      <circle
        cx="12"
        cy="12"
        r="9"
        stroke="currentColor"
        strokeDasharray="38 57"
        strokeLinecap="round"
        strokeWidth={strokeWidth}
        transform="rotate(-90 12 12)"
      />
    </SvgIcon>
  );
}

